from collections import deque

class HopcroftKarp:
    def __init__(self, n_left, n_right):
        self.n_left = n_left
        self.n_right = n_right
        self.adj = [[] for _ in range(n_left)]
        self.match_left = [-1] * n_left
        self.match_right = [-1] * n_right
        self.dist = [float('inf')] * (n_left + 1) # dist[u] for u in L, dist[n_left] for NIL

    def add_edge(self, u, v):
        self.adj[u].append(v)

    def bfs(self):
        Q = deque()
        for u in range(self.n_left):
            if self.match_left[u] == -1:
                self.dist[u] = 0
                Q.append(u)
            else:
                self.dist[u] = float('inf')

        self.dist[self.n_left] = float('inf') # For NIL node

        while Q:
            u = Q.popleft()

            if self.dist[u] < self.dist[self.n_left]:
                for v in self.adj[u]:
                    if self.match_right[v] == -1: # v is unmatched in R. Path u -> v -> NIL found.
                        self.dist[self.n_left] = min(self.dist[self.n_left], self.dist[u] + 1)
                    else: # v is matched with u_prime = self.match_right[v]
                        u_prime = self.match_right[v]
                        if self.dist[u_prime] == float('inf'): # If u_prime not yet visited at this depth
                            self.dist[u_prime] = self.dist[u] + 1
                            Q.append(u_prime)

        return self.dist[self.n_left] != float('inf')

    def dfs(self, u):
        if u == self.n_left: # Reached NIL (end of an augmenting path)
            return True

        if self.dist[u] == float('inf'): # If u is already marked as unreachable or processed
             return False

        for v in self.adj[u]:
            # Case 1: v is unmatched. It effectively reaches NIL.
            if self.match_right[v] == -1:
                if self.dist[self.n_left] == self.dist[u] + 1: # If NIL is at the expected next level
                    self.match_right[v] = u
                    self.match_left[u] = v
                    return True
            # Case 2: v is matched with u_prime
            else:
                u_prime = self.match_right[v]
                if self.dist[u_prime] == self.dist[u] + 1: # If u_prime is at the expected next level
                    if self.dfs(u_prime): # Recursively try to extend the path from u_prime
                        self.match_right[v] = u
                        self.match_left[u] = v
                        return True

        self.dist[u] = float('inf') # Mark u as dead end for current layered graph
        return False

    def max_matching(self):
        matching_size = 0
        while self.bfs():
            for u in range(self.n_left):
                if self.match_left[u] == -1: # Only try to extend paths from unmatched nodes in L
                    if self.dfs(u):
                        matching_size += 1
        return matching_size
